import { describe, expect, it, vi } from "vitest";

describe("PgUsers", () => {
  it("one() returns null when no row exists", async () => {
    const db = { query: vi.fn().mockResolvedValue({ rows: [] }) };
    const users = new PgUsers(db as unknown as DatabaseClient);

    await expect(users.one("u1")).resolves.toBeNull();
    expect(db.query).toHaveBeenCalledWith(
      "select id, email from users where id = $1",
      ["u1"],
    );
  });

  it("one() maps the first row with String()", async () => {
    const db = {
      query: vi.fn().mockResolvedValue({
        rows: [{ id: 42, email: { toString: () => "a@b.com" } }],
      }),
    };
    const users = new PgUsers(db as unknown as DatabaseClient);

    await expect(users.one("u1")).resolves.toEqual({
      id: "42",
      email: "a@b.com",
    });
  });

  it("all() preserves database order and maps every row with String()", async () => {
    const db = {
      query: vi.fn().mockResolvedValue({
        rows: [
          { id: 2, email: "b@x.com" },
          { id: 1, email: null },
        ],
      }),
    };
    const users = new PgUsers(db as unknown as DatabaseClient);

    await expect(users.all()).resolves.toEqual([
      { id: "2", email: "b@x.com" },
      { id: "1", email: "null" },
    ]);
    expect(db.query).toHaveBeenCalledWith(
      "select id, email from users order by id",
    );
  });
});
